import psycopg2
from psycopg2 import sql
import sys

def install_extension(connection_params, extension_name):
    try:
        conn = psycopg2.connect(**connection_params)
        cursor = conn.cursor()
        
        create_extension_query = sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(
            sql.Identifier(extension_name)
        )
        
        cursor.execute(create_extension_query)
        conn.commit()
        
        print(f"Extension '{extension_name}' installed successfully.")
        
        cursor.close()
        conn.close()
        
    except psycopg2.Error as e:
        print(f"Error installing extension '{extension_name}': {e}")
        if conn:
            conn.rollback()
        return False
    except Exception as e:
        print(f"Unexpected error: {e}")
        return False
    
    return True

def main():
    # Database connection parameters
    connection_params = {
        'host': 'localhost',
        'port': 5432,
        'database': 'your_database',
        'user': 'your_username',
        'password': 'your_password'
    }
    
    # Get extension names from user input
    extensions_input = input("Enter extension names separated by commas: ")
    extension_names = [ext.strip() for ext in extensions_input.split(',')]
    
    # Install each extension
    for extension_name in extension_names:
        if extension_name:
            install_extension(connection_params, extension_name)

if __name__ == "__main__":
    main()